#include <stdio.h>
#include <stdbool.h>

#define MAX_THREADS 10

typedef struct {
    int thread_id;
    int burst_time;
    int priority;  // Lower number = higher priority
    int waiting_time;
} Thread;

void priority_scheduling_with_aging(Thread threads[], int n) {
    int current_time = 0;
    int completed = 0;
    bool visited[MAX_THREADS] = {false};

    while (completed < n) {
        int highest_priority = 999;
        int selected = -1;

        // Find thread with highest priority (lowest number)
        // Also apply aging: increase priority based on waiting
        for (int i = 0; i < n; i++) {
            if (!visited[i] && threads[i].priority < highest_priority) {
                highest_priority = threads[i].priority;
                selected = i;
            } else if (!visited[i] && threads[i].priority == highest_priority) {
                // Tie-breaker: earlier arrival
                if (selected == -1 || threads[i].waiting_time > threads[selected].waiting_time) {
                    selected = i;
                }
            }
        }

        if (selected != -1) {
            // Execute selected thread
            current_time += threads[selected].burst_time;
            threads[selected].waiting_time = current_time - threads[selected].burst_time;
            visited[selected] = true;
            completed++;

            printf("Thread %d executed, Priority: %d, Wait: %d\n", 
                   threads[selected].thread_id, 
                   threads[selected].priority,
                   threads[selected].waiting_time);

            // Aging: Increase priority of waiting threads
            for (int i = 0; i < n; i++) {
                if (!visited[i]) {
                    threads[i].priority -= 1;  // Higher priority (lower number)
                }
            }
        }
    }
}
